import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "./styles/Books.css";
import { data } from "./CategoryBooksData";


function BorrowedBooks() {
  const [books, setBooks] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const borrowed = [];

    for (let key in localStorage) {
      if (localStorage.getItem(key) === "borrowed") {
        borrowed.push(key);
      }
    }

    setBooks(borrowed);
  }, []);

  const returnBook = (title) => {
    localStorage.removeItem(title);
    setBooks(books.filter(b => b !== title));
  };

  return (
    <div className="books-page">
      <h1 className="books-title">My Borrowed Books</h1>

      {books.length === 0 ? (
        <p style={{color:"#6b4a30"}}>No books borrowed yet.</p>
      ) : (
        <div className="books-grid">
          {books.map((title, i) => (
            <div key={i} className="book-card">
              <h3>{title}</h3>

              <button
                className="return-btn"
                onClick={() => returnBook(title)}
              >
                Return Book
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default BorrowedBooks;
